@implements IAsyncDisposable
@inject IProductService ProductService

<div class="product-search">
    <input type="text"
           placeholder="Search products…"
           value="@searchText"
           @oninput="HandleInput" />

    @if (isLoading)
    {
        <p class="product-search-status">Searching…</p>
    }
    else if (errorMessage is not null)
    {
        <p class="product-search-error">@errorMessage</p>
    }
    else if (products is { Count: 0 })
    {
        <p class="product-search-status">No products found.</p>
    }

    @if (products is { Count: > 0 })
    {
        <div class="product-search-results">
            @foreach (var product in products)
            {
                <div class="product-card" @key="product.Id"
                     @onclick="() => OnProductSelected.InvokeAsync(product)">
                    <img src="@product.ImageUrl" alt="@product.Name" />
                    <span class="product-card-name">@product.Name</span>
                    <span class="product-card-price">@product.Price.ToString("C")</span>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<Product> OnProductSelected { get; set; }

    private string searchText = string.Empty;
    private List<Product>? products;
    private bool isLoading;
    private string? errorMessage;
    private CancellationTokenSource? cts;

    private async Task HandleInput(ChangeEventArgs e)
    {
        searchText = e.Value?.ToString() ?? string.Empty;

        // Cancel any previous debounce / in-flight search.
        cts?.Cancel();
        cts?.Dispose();
        cts = new CancellationTokenSource();
        var token = cts.Token;

        if (string.IsNullOrWhiteSpace(searchText))
        {
            products = null;
            errorMessage = null;
            isLoading = false;
            return;
        }

        try
        {
            // Debounce: wait 300 ms; cancelled if user types again.
            await Task.Delay(300, token);

            isLoading = true;
            errorMessage = null;
            StateHasChanged();

            products = await ProductService.SearchAsync(searchText, token);
            isLoading = false;
        }
        catch (OperationCanceledException)
        {
            // Superseded by a newer keystroke — nothing to do.
        }
        catch (Exception ex)
        {
            isLoading = false;
            products = null;
            errorMessage = $"Search failed: {ex.Message}";
        }
    }

    public ValueTask DisposeAsync()
    {
        cts?.Cancel();
        cts?.Dispose();
        return ValueTask.CompletedTask;
    }
}

